# Use Diffusers VAE encoder for latent extraction
from diffusers import AutoencoderKL
import torch

# Load pre-trained SD VAE encoder (downloads ~330MB weights on first call)
# vae = AutoencoderKL.from_pretrained("stabilityai/sd-vae-ft-mse")
# vae.eval()

# Simulated usage (without downloading weights):
class MockVAE:
    def encode(self, x):
        class LatentDist:
            def sample(self):
                B, C, H, W = x.shape
                return torch.randn(B, 4, H//8, W//8)
        class Result:
            latent_dist = LatentDist()
        return Result()

vae = MockVAE()
pixel_values = torch.randn(1, 3, 512, 512)
with torch.no_grad():
    latents = vae.encode(pixel_values).latent_dist.sample()
latents = latents * 0.18215    # SD scaling factor (learned empirically)
print(f"Pixel space: {pixel_values.shape}  Latent space: {latents.shape}")
# → Pixel space: (1, 3, 512, 512)  Latent space: (1, 4, 64, 64)
